import{_ as d,o as a,c as n,a2 as s}from"./chunks/framework.BnBoz4Zl.js";const r="/anjian-workbuddy-bluebook-site/assets/001_image_RklAba93No.D3pMvC3n.png",e="/anjian-workbuddy-bluebook-site/assets/002_image_MhojbPRsOo.Bk_C8hGc.png",o="/anjian-workbuddy-bluebook-site/assets/003_image_Ff6fbYuGoo.Db0vIclN.png",m=JSON.parse('{"title":"第 10 章 WorkBuddy 自动化任务","description":"::: warning 安居建业内部使用提示 自动化上线前必须明确数据来源、运行账号、工作目录、输出去向、失败回退和责任人。删除、覆盖、外发、审批和投资判断等动作不得默认无人值守执行；应设置人工确认点、幂等保护、运行日志和可停止机制，并先用脱敏样本演练。 :::","frontmatter":{},"headers":[],"relativePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 10 章 WorkBuddy 自动化任务/index.md","filePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 10 章 WorkBuddy 自动化任务/index.md","lastUpdated":1784771354000}'),p={name:"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 10 章 WorkBuddy 自动化任务/index.md"};function l(i,t,h,c,b,u){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="第-10-章-workbuddy-自动化任务" tabindex="-1">第 10 章 WorkBuddy 自动化任务 <a class="header-anchor" href="#第-10-章-workbuddy-自动化任务" aria-label="Permalink to &quot;第 10 章 WorkBuddy 自动化任务&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">安居建业内部使用提示</p><p>自动化上线前必须明确数据来源、运行账号、工作目录、输出去向、失败回退和责任人。删除、覆盖、外发、审批和投资判断等动作不得默认无人值守执行；应设置人工确认点、幂等保护、运行日志和可停止机制，并先用脱敏样本演练。</p></div><p>真正消耗人的，往往不是那些需要创造力的大任务，而是每天都要打开同样的页面、收集相似的信息、整理成同一种格式，再把结果发给同一批人。WorkBuddy 自动化的价值，就是把这些“时间固定、步骤相似、结果可检查”的工作变成可重复运行的 Agent 任务。</p><h2 id="为什么-workbuddy-可以自动化" tabindex="-1">为什么 WorkBuddy 可以自动化 <a class="header-anchor" href="#为什么-workbuddy-可以自动化" aria-label="Permalink to &quot;为什么 WorkBuddy 可以自动化&quot;">​</a></h2><p>传统自动化通常要求人先把每一个步骤写成代码：打开哪个系统、点击哪个按钮、读取哪一列、遇到异常怎么分支。</p><p>WorkBuddy 的不同之处，是把“定时调度”与 Agent 的理解、工具调用和文件处理能力组合起来。你不必把所有细节都写成程序，但需要把目标、输入、边界和结果说清楚。</p><p>自动化配置保存在本地客户端，包括任务名称、提示词、调度规则、工作目录和执行状态。到达设定时间后，WorkBuddy 会沿用当前登录身份发起 Agent 任务，并按提示词调用模型、Skill、MCP 或连接器，在指定工作目录完成查询、汇总和文件处理。</p><p>真正让任务稳定运行的是五个要素：明确的触发时间、可重复的输入来源、足够具体的 Prompt、固定且受控的工作目录，以及能够判断成功或失败的验收条件。</p><h2 id="自动化能用来做什么" tabindex="-1">自动化能用来做什么 <a class="header-anchor" href="#自动化能用来做什么" aria-label="Permalink to &quot;自动化能用来做什么&quot;">​</a></h2><p>最直观的用途是把每天、每周、每月都要重复的工作交给 WorkBuddy。价值不只在于少点几次鼠标，而在于任务不会因为忙碌而被遗忘，执行方法也不会随着不同的人临时变化。</p><table tabindex="0"><thead><tr><th>场景</th><th>可以自动完成</th><th>典型产物</th></tr></thead><tbody><tr><td>资讯与情报</td><td>定时搜索行业新闻、政策、竞品动态，去重后摘要</td><td>每日简报、风险提示、来源清单</td></tr><tr><td>日报与周报</td><td>汇总任务、日历、文档和数据变化，按固定结构生成报告</td><td>日报、周报、项目进度表</td></tr><tr><td>数据与表格</td><td>收集文件、合并表格、清洗字段、检查缺失和异常</td><td>对账表、异常清单、趋势图</td></tr><tr><td>文件管理</td><td>按日期和项目归档、批量重命名、抽取 PDF 或图片文字</td><td>归档目录、索引、处理日志</td></tr><tr><td>信息整理</td><td>收集公开信息、生成候选、整理来源、制作发布草稿</td><td>候选清单、核验表、发布草稿</td></tr><tr><td>知识管理</td><td>定时整理收藏、会议纪要和灵感，补标签与来源</td><td>知识卡片、每周回顾、待消化列表</td></tr><tr><td>系统巡检</td><td>巡检日志、汇总异常、检查依赖和运行结果</td><td>巡检报告、异常摘要、处理建议</td></tr><tr><td>培训复盘</td><td>汇总学习材料、练习结果和待解决问题</td><td>学习清单、复盘记录、问题清单</td></tr></tbody></table><h2 id="什么样的任务适合先自动化" tabindex="-1">什么样的任务适合先自动化 <a class="header-anchor" href="#什么样的任务适合先自动化" aria-label="Permalink to &quot;什么样的任务适合先自动化&quot;">​</a></h2><p>可以用下面六个问题做判断。回答“是”越多，越适合作为第一批自动化任务：</p><ol><li><strong>会重复吗</strong>：至少每周发生一次，而不是一次性需求；</li><li><strong>输入稳定吗</strong>：文件夹、网页、表格或连接器来源相对固定；</li><li><strong>步骤相似吗</strong>：虽然内容变化，但处理方式基本一致；</li><li><strong>结果可验收吗</strong>：能检查条数、字段、时间范围、来源或文件是否生成；</li><li><strong>失败可恢复吗</strong>：失败后可以重跑，不会立即造成不可逆损失；</li><li><strong>权限可控制吗</strong>：可以限定工作目录、账号和允许调用的工具。</li></ol><p>最适合的起点，通常不是“替我运营整个公司”，而是“每天 8 点收集 10 条 AI 行业新闻，去重、保留链接，生成 Markdown 简报到指定目录”。范围越清楚，越容易发现问题并逐步改进。</p><h2 id="从一句想法到可运行任务" tabindex="-1">从一句想法到可运行任务 <a class="header-anchor" href="#从一句想法到可运行任务" aria-label="Permalink to &quot;从一句想法到可运行任务&quot;">​</a></h2><p>创建自动化前，先把口头需求改写成一份小型任务说明。一个可靠的 Prompt 至少要回答：何时执行、读取什么、怎样处理、输出到哪里、怎样算完成、失败后怎么办、哪些动作禁止执行。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>任务名称：每日 AI 行业简报</span></span>
<span class="line"><span>触发时间：每天 08:00，时区 Asia/Shanghai</span></span>
<span class="line"><span>工作目录：automation/ai-daily</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输入：</span></span>
<span class="line"><span>- 检索过去 24 小时的 AI 产品、模型和行业新闻</span></span>
<span class="line"><span>- 仅使用可以访问并保留链接的公开来源</span></span>
<span class="line"><span></span></span>
<span class="line"><span>处理规则：</span></span>
<span class="line"><span>1. 合并重复事件，按产品、技术、商业三类整理</span></span>
<span class="line"><span>2. 每条包含标题、100 字摘要、来源、发布时间和链接</span></span>
<span class="line"><span>3. 无法确认发布时间或来源的内容放入“待核验”，不要编造</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出：</span></span>
<span class="line"><span>- 保存为 YYYY-MM-DD-ai-daily.md</span></span>
<span class="line"><span>- 正文最多 10 条，最后附来源清单</span></span></code></pre></div><h2 id="创建一项自动化任务" tabindex="-1">创建一项自动化任务 <a class="header-anchor" href="#创建一项自动化任务" aria-label="Permalink to &quot;创建一项自动化任务&quot;">​</a></h2><p>在 WorkBuddy 打开“自动化”页面，可以查看已安排任务和历史执行记录。点击“添加”后，需要配置任务名称、工作空间、提示词、模型与技能、定时规则，以及是否把完成结果推送到 WorkBuddy 小程序。</p><table tabindex="0"><thead><tr><th>配置项</th><th>作用</th><th>填写建议</th></tr></thead><tbody><tr><td>名称</td><td>区分不同自动化任务</td><td>写清对象和频率，如“每日 AI 简报”</td></tr><tr><td>工作空间</td><td>限定执行目录和文件保存位置</td><td>为每项自动化使用独立目录，避免互相覆盖</td></tr><tr><td>提示词</td><td>描述目标、步骤、输出和边界</td><td>使用上面的任务模板，不只写一句口号</td></tr><tr><td>模型和技能</td><td>决定可用的理解与执行能力</td><td>只选择任务真正需要的 Skill 和连接器</td></tr><tr><td>定时规则</td><td>设置频率和生效日期</td><td>先低频试运行，再逐步提高频率</td></tr><tr><td>推送到小程序</td><td>完成后在手机查看结果</td><td>开启前确认哪些结果会通过安全链路同步到云端</td></tr></tbody></table><p>点击“自动化”，</p><p><img src="`+r+'" alt="" loading="lazy"></p><p>“添加自动化”，就可以自定义你的任务</p><p><img src="'+e+'" alt="" loading="lazy"></p><p>比如，每日AI资讯新闻推送，定时8点发送</p><p><img src="'+o+'" alt="" loading="lazy"></p><h2 id="不想从零写-prompt-可以先用模板" tabindex="-1">不想从零写 Prompt，可以先用模板 <a class="header-anchor" href="#不想从零写-prompt-可以先用模板" aria-label="Permalink to &quot;不想从零写 Prompt，可以先用模板&quot;">​</a></h2><p>官方任务模板覆盖新闻推送、周报生成、体检预约和学习计划等常见场景。模板的价值是提供基本字段和任务结构，但它不是最终答案。选用后仍应修改数据来源、时间范围、输出位置、验收标准和禁止动作。</p><h2 id="更多值得尝试的自动化场景" tabindex="-1">更多值得尝试的自动化场景 <a class="header-anchor" href="#更多值得尝试的自动化场景" aria-label="Permalink to &quot;更多值得尝试的自动化场景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>任务</th><th>触发方式</th><th>建议保留的人工检查</th></tr></thead><tbody><tr><td>周报汇总</td><td>每周五读取本周任务、日历和交付文件</td><td>确认进度和风险表述后再发送</td></tr><tr><td>销售日报</td><td>每天汇总 CRM 或表格中的新增客户与跟进记录</td><td>核对金额、客户状态和负责人</td></tr><tr><td>费用与发票整理</td><td>每月读取指定目录中的票据和报销表</td><td>财务提交前核对税额、重复票据和归属</td></tr><tr><td>公开信息候选池</td><td>定期收集政策、行业话题和公开问题</td><td>人工筛选、核验并确认是否采用</td></tr><tr><td>知识库周回顾</td><td>每周整理新增笔记、收藏和会议纪要</td><td>确认分类、来源和是否值得长期保留</td></tr><tr><td>项目风险巡检</td><td>每天检查延期任务、构建结果和错误日志</td><td>严重告警交由负责人确认处置</td></tr><tr><td>竞品价格监控</td><td>定时读取公开页面或授权 API</td><td>页面结构变化时暂停并修复解析规则</td></tr><tr><td>学习计划复盘</td><td>每天提醒，周末汇总完成情况</td><td>根据真实精力调整下周计划</td></tr></tbody></table>',31)])])}const g=d(p,[["render",l]]);export{m as __pageData,g as default};
